const raw = $input.first().json;
const d = raw.body || raw.query || raw;
d.runtime_mode = d.runtime_mode || "MOCK";
d.correlation_id = d.correlation_id || ("COML-" + Date.now());
d.request_id = d.request_id || ("REQ-" + Math.random().toString(36).substr(2,8).toUpperCase());
d.user = d.user || {id:"system",name:"Auto",role:"agent",department:"comercial"};
d.payload = d.payload || {};
d.metadata = d.metadata || {};
const pl = d.payload;
const msg = (d.message||"").toLowerCase();
if(!d.action){
  if(pl.body||pl.from||pl.subject) d.action="email_intake";
  else if(pl.proposal_id && pl.approved===true) d.action="generate_pdf";
  else if(/proposta|or.amento|cliente/.test(msg)) d.action="intake";
  else d.action="intake";
}
return [{json:d}];

const d = $input.first().json;
let body = d.payload?.body || d.message || "";
body = body.replace(/^>.*$/gm,"").replace(/_{10,}/g,"").replace(/De:.*\nEnviado:.*\nPara:.*/gm,"");
body = body.replace(/\n{3,}/g,"\n\n").trim();
d._cleaned_body = body;
return [{json:d}];

const d = $input.first().json;
const pl = d.payload || {};
const action = d.action || "intake";
const body = d._cleaned_body || d.message || "";
if(["generate_pdf","send_proposal","schedule_followup","win_loss","request_approval"].includes(action)){
  d._validation={valid:true,missing:[]};d._needs_info=false;return [{json:d}];
}
const missing = [];
const hasCustomer = pl.customer?.company_name||pl.customer?.email||pl.from;
const hasProduct = pl.requested_products?.length||pl.requested_service||body.length>20;
if(!hasCustomer) missing.push("customer");
if(!hasProduct) missing.push("requested_products");
d._validation={valid:missing.length===0,missing};
d._needs_info=missing.length>0;
return [{json:d}];

const d = $input.first().json;
const pl = d.payload || {};
const text = (d._cleaned_body||d.message||pl.body||"").toLowerCase();
const sub = (pl.subject||"").toLowerCase();
const full = text + " " + sub;
const cust = pl.customer || {};
const exInmetro = /\\bex\\b|area classificada|inmetro|zona explosiva|a prova de explos/.test(full);
const competitor = /outra empresa|concorrente|mais barato|recebi proposta|cotação de outra/.test(full);
let category = "geral";
if(/exaustor/.test(full)) category="exaustor";
else if(/ventilador|ventfog/.test(full)) category="ventilador";
else if(/climatizador|climatiza/.test(full)) category="climatizacao";
else if(/cortina de ar/.test(full)) category="cortina_ar";
else if(/micro.?ventilador/.test(full)) category="microventilador";
let proposal_type = "venda";
if(/loca.{0,5}o|aluguel/.test(full)) proposal_type="locacao";
else if(/manuten.{0,5}o|conserto|reparo/.test(full)) proposal_type="manutencao";
else if(/servi.{0,5}o/.test(full)) proposal_type="servico";
const qtyM = full.match(/(\\d+)\\s*(unidade|un|pe.a|equipamento)/);
d._customer = {
  company_name: cust.company_name || pl.from?.split("@")[0] || "Nao identificado",
  email: cust.email || pl.from || "",
  contact_name: cust.contact_name || "",
  phone: cust.phone || "",
  cnpj: cust.cnpj || "",
  address: cust.address || ""
};
d._demand = {
  requested_products: pl.requested_products || [category],
  product_category: category,
  proposal_type,
  quantity: pl.quantity || (qtyM?qtyM[1]:"1"),
  deadline: pl.deadline || "",
  technical_specs: pl.technical_specs || "",
  budget: pl.budget || 0,
  urgency: /urgent|urgente|r.pido/.test(full)?"alta":"normal",
  ex_inmetro_related: exInmetro,
  competitor_mentioned: competitor,
  image_analysis_required: false,
  pdf_analysis_required: (pl.attachments||[]).length>0
};
return [{json:d}];

const d = $input.first().json;
const email = d._customer?.email || "";
const company = d._customer?.company_name || "";
d._customer_lookup = d.runtime_mode==="PORTAL" ? {
  note:"TODO: GET /api/clientes/search?query="+encodeURIComponent(company),
  customer_id: null, customer_status:"unknown"
} : {
  customer_id: "CUST-MOCK-" + Math.random().toString(36).substr(2,6).toUpperCase(),
  customer_status: email.includes("@") ? "existing" : "new",
  last_proposal_date: "2025-01-15",
  commercial_owner: "Vendedor Vesper",
  risk_notes: []
};
d._customer.id = d._customer_lookup.customer_id;
return [{json:d}];

