  scheduled_date: new Date(Date.now()+days*86400000).toISOString().split("T")[0],
  note: d.runtime_mode==="PORTAL"?"TODO: POST /api/propostas/{id}/followup":"MOCK: followup agendado"
};
d._status="followup_scheduled";
return [{json:d}];

const d = $input.first().json;
if(d._demand?.ex_inmetro_related && !["technical_review_required","approval_pending"].includes(d._status)){
  d._risk_level="critical";d._requires_approval=true;
  if(d._status==="draft_created") d._status="technical_review_required";
}
if(d._demand?.competitor_mentioned && d._risk_level==="low") d._risk_level="high";
const evtMap = {
  "intake":"comercial.intake_received","email_intake":"comercial.intake_received",
  "create_draft":"comercial.draft_created","technical_review":"comercial.technical_review_required",
  "request_approval":"comercial.approval_requested","generate_pdf":"comercial.pdf_ready",
  "send_proposal":"comercial.proposal_send_placeholder","schedule_followup":"comercial.followup_scheduled"
};
d._audit = {
  event_type: evtMap[d.action]||"comercial.processed",
  correlation_id: d.correlation_id, request_id: d.request_id,
  action: d.action, status: d._status,
  customer: d._customer||{}, risk_level: d._risk_level||"low",
  runtime_mode: d.runtime_mode, timestamp: new Date().toISOString(),
  note: d.runtime_mode==="PORTAL"?"TODO: POST /api/automation/audit":"MOCK: audit_logged=true"
};
return [{json:d}];

const d = $input.first().json;
